+func TestIsNumericPort(t *testing.T) {
+	cases := map[string]bool{
+		"":      false,
+		"0":     true,
+		"443":   true,
+		"65535": true,
+		"abc":   false,
+		"4a":    false,
+		"db8":   false, // IPv6 hex segment, NOT a port
+	}
+	for in, want := range cases {
+		if got := isNumericPort(in); got != want {
+			t.Errorf("isNumericPort(%q) = %v, want %v", in, got, want)
+		}
+	}
+}
